-- ============================================================
-- CARGA DE EJERCICIOS v2 - CON LINKS REALES
-- Coach: anto.au.almanza@gmail.com
-- Total: 142 ejercicios
-- INSTRUCCIONES: correr en el SQL Editor de Supabase
-- ============================================================

DO $$
DECLARE
  coach_id uuid;
BEGIN
  -- Buscar UUID del coach (no falla si no se encuentra)
  SELECT id INTO coach_id
  FROM public.profiles
  WHERE email = 'anto.au.almanza@gmail.com'
  LIMIT 1;

  IF coach_id IS NULL THEN
    RAISE WARNING 'Coach no encontrada. Se insertarán los ejercicios sin created_by.';
  ELSE
    RAISE NOTICE 'Coach encontrada: %', coach_id;
  END IF;

  -- Eliminar ejercicios anteriores de esta carga (evitar duplicados si se corre 2 veces)
  DELETE FROM public.exercises
  WHERE created_by = coach_id
     OR (coach_id IS NULL AND created_by IS NULL);


  RAISE NOTICE 'Carga completada: 142 ejercicios insertados.';
END $$;