  INSERT INTO public.exercises (name, muscle_group, video_url, technique_notes, created_by)
  VALUES
    ('Bracing', 'ACTIVACION', 'https://www.youtube.com/shorts/fneNu_RcUkI', 'respiracion disfragmatica (solo por abdomen) para aplicarla en el resto de los ejercicios y mantener una estabilidad central q nos proteja la columna', coach_id),
    ('Sentadilla Lateral Con Deficit', 'ACTIVACION', 'https://drive.google.com/file/d/194KHpDFKOpMPnDh7n6oqRckkU-YpgfTo/view?usp=sharing', 'Pierna que NO esta en el step siempre extendida. rodillas hacia afuera. fuerza con espalda para mantenerla derecha.', coach_id),
    ('Spiderman Molino', 'ACTIVACION', 'https://drive.google.com/file/d/1w5IEMl8ca1z87N2YmZnpC5YaYVo7l-wu/view?usp=drive_link', 'Rodilla de adelante en rotacion externa. movimiento del brazo es lineal, que no se vaya para abajo. evito pegar el hombro de la mano q no se mueve a la cabeza.', coach_id),
    ('Tobillo', 'ACTIVACION', 'https://drive.google.com/file/d/1hE8vYELXtpTpILmHrpQFq78Wlkf70W0t/view?usp=sharing', 'Tiro rodilla lo mas adelante posible, no el cuerpo. solo rodilla. sin levantar talon.', coach_id),
    ('Ajuste Colgada', 'ACTIVACION', 'https://drive.google.com/file/d/1R2cc8iw203qS7iMhGlLmVYK5bCoVaS8X/view?usp=sharing', 'codos NO se flexionan nunca. es hacer un movimiento de "que me importa" con los hombros ascendiendo y descendiendo los mismos.', coach_id),
    ('Sentadilla Lateral A Spiderman Molino Con Codo', 'ACTIVACION', 'https://drive.google.com/file/d/1vRzacGR_Jm35mkUdROdsL4ApHUksy-su/view?usp=sharing', 'hacerlo con codo. rodilla bien extendida. la otra  adelantada en rotacion externa. evito pegar hombro a oreja en todo momento del movimiento', coach_id),
    ('Hombro Con Palo', 'ACTIVACION', 'https://drive.google.com/file/d/1rv9SAMwjEprWemd76v51FZa0LptkBMet/view?usp=sharing', 'mientras mas angosto el agarre mas dificil. evitar arquear espalda o subir hombros. ajusto core llevando ombligo hacia la lumbar', coach_id),
    ('Carpa', 'ACTIVACION', 'https://drive.google.com/file/d/1sa3TeW_4JtLHQkz9_7nv7MC1HlKSmlz3/view?usp=sharing', 'posicion de plancha, subo cadera y busco meter cabeza lo mas adentro posible, sacar cola y buscar talon al suelo. no despego apoyo de pies o manos NUNCA', coach_id),
    ('Split P/ Tobillo', 'ACTIVACION', 'https://drive.google.com/file/d/1tgmgbJEA6GOcIMVmfftOGxJ-efLphPbT/view?usp=sharing', 'trato de llevar la rodilla de adelante lo mas adelante posible sin que se levante el talon. espalda derecha. puede hacerse con un peso en cada mano o solo uno. no importa el lado', coach_id),
    ('Pull Apart', 'ACTIVACION', 'https://drive.google.com/file/d/1STQ2J43YjYdCHlN18jkJM7i_1y7oRbvl/view?usp=sharing', 'PALMAS ARRIBA. mientras mas cerca el agarre mas dificil, codos siempre extendidos marco abduccion horizontal juntando escapulas atras. evitar levantar hombros o arquear espalda', coach_id),
    ('Chinito', 'ACTIVACION', 'https://drive.google.com/file/d/1rOQdxn0-8WyPJkIomSZUo0bTbwiPGVqd/view?usp=sharing', 'gluteos activos. rodillas hacia afuera. junto escapulas. toda la planta del pie apoyada', coach_id),
    ('"Goblet Hold Dead Lift', 'ACTIVACION', 'https://drive.google.com/file/d/1ep_9CtC3Jo_CB_HRzZpmdtHbM4AFDj7i/view?usp=sharing', 'marco bisagra de cadera. la cadera por atras de la linea de la rodilla y del pie. rodillas hacia afuera', coach_id),
    ('Sumo Walk', 'ACTIVACION', 'https://drive.google.com/file/d/1nGmNpwnrHgikdF3b2j0Jqftxn8RN7yIQ/view?usp=sharing', 'rotacion externa de rodilla todo el tiempo. semi flexion de rodilla', coach_id),
    ('Tempo Sq', 'ACTIVACION', 'https://drive.google.com/file/d/19ikoHF8Nr4BmrQi3S6FAy17QUwKUgu7-/view?usp=sharing', '3 seg para bajar. 2 seg mantengo y 1 seg para subir. aplico bracing.  rodillas hacia afuera y uso taco en talones.', coach_id),
    ('W A Y Posicion Supina', 'ACTIVACION', 'https://drive.google.com/file/d/1ErvPXYjS_BdHPorRAs5zA6Uup_Jbb7V-/view?usp=sharing', 'junto escapulas al marcar w y trato de no pegar hombros a oreja cuando extiendo los codos a Y', coach_id),
    ('Gluteo Medio Contra Pelota', 'ACTIVACION', 'https://drive.google.com/file/d/1xlJwkJMk70bstTaFvN3tREb5qO4dNIGG/view?usp=sharing', 'fuerza constante e isometrica. hacerlo sin apoyar rodilla. aplico bracing', coach_id),
    ('Molino Arrodillada', 'ACTIVACION', 'https://drive.google.com/file/d/13DIEjQctycqGTph1xRBQnk0kdlOwqtms/view?usp=sharing', 'hacerlo apoyando mano. aplico bracing. pesa de 6 u 8 kilos para empezar', coach_id),
    ('Standing Banded Hip Abduction/Adduction', 'ACTIVACION', 'https://drive.google.com/file/d/1xYBGZMpyZ03ZpBgAn4SMu0v6VkqZs4T0/view?usp=sharing', 'rodillas rotacion externa. evito abrir la cadera. semiflexion de rodilla.', coach_id),
    ('Molino Con Aductor', 'ACTIVACION', 'https://drive.google.com/file/d/19sa4Lhq0YBv47bevRVmxfhS-XJeohEB8/view?usp=sharing', 'separo rodillas lo mas posible. mantengo neutralidad en columna (no exagerar meter o sacar cola). mano en nuca, el codo busca antebrazo contrario y busco rotar lo mas posible. EVITO ELEVAR HOMBROS', coach_id),
    ('Colgarse', 'ACTIVACION', 'https://drive.google.com/file/d/11nr8VV0YHco-0MFSa8CUcJSficacUnyN/view?usp=sharing', 'Agarre completo de la mano sobre la barra/ me dejo colgar y suelto todo el cuerpo', coach_id),
    ('Glute Bridge', 'ACTIVACION', 'https://drive.google.com/file/d/16QkfqvLlGnNKHtSkYi-X0Lw4KRcbkXG-/view?usp=sharing', 'Cadera alineada. tomo aire abajo. mantengo mientras subo y suelto al bajar.', coach_id),
    ('Plancha Aplicando Bracing', 'ACTIVACION', 'https://drive.google.com/file/d/1oudK45E0oKePr6JeqfGR0CyItAzz64oh/view?usp=sharing', 'alineo hombro y cadera. aplico bracing. suelto el aire ajustando el abdomen.', coach_id),
    ('Goblet Sq Con Peso Y Cajon/Step', 'ACTIVACION', 'https://drive.google.com/file/d/1lJIeEGl_6ISmUn-Ne_d4_HNaawAqiLrD/view?usp=sharing', 'Talones pegados al step. rodillas afuera. peso distribuido en toda la planta del pie', coach_id),
    ('"W" "Y" Shoulder Mobility  W/Band', 'ACTIVACION', 'https://drive.google.com/file/d/1GY664oJw6ioLzPvM5yAkDopHc7c1cjH0/view?usp=sharing', 'la cabeza puede ir apoyada en un cuadrado o en un buzo para mas comodidad. tension de la banda constante. al marcar W  junto escapulas.', coach_id),
    ('Chinito Con Banda Sin Apoyar Codos', 'ACTIVACION', 'https://drive.google.com/file/d/152Lp7ZWMEwiiiy7okwlpvHjnqeBi7yCG/view?usp=sharing', 'la fuerza de rodillas hacia afuera activa constentamente. banda POR ABAJO de la rodilla. junto escapulas atras. gluteos activos, que no se caiga la cola', coach_id),
    ('Bisagra Cadera Con Powerband', 'ACTIVACION', 'https://drive.google.com/file/d/1BLywHhkFl6GJBCzOTaKQW7hWCxhvD0MQ/view?usp=sharing', 'agarre de pies al suelo estables y rigidos, tiro solo rodillas hacia afuera . me dejo llevar con cadera hacia atras por fuerza de powerband, peso pegado al pecho, y le gano a la resistencia metiendo cola.', coach_id),
    ('Spiderman Open Book', 'ACTIVACION', 'https://drive.google.com/file/d/12qfwNrZB08LWk7Osi5ky1iJ0zVjmKx5X/view?usp=sharing', 'rodilla de atras bien extendida, junto escapulas  una vez que marco apertura con brazos', coach_id),
    ('Candelabro Arrodillada', 'ACTIVACION', 'https://drive.google.com/file/d/18EDHpYIatlxZaBRPPCVrOojP--FC57Zp/view?usp=sharing', 'evito arquear espalda en todo momento. palmas hacia abajo en todo momento. la idea es subir antebrazos y codos a la altura del hombro.', coach_id),
    ('Estrella Con Conos', 'ACTIVACION', 'https://drive.google.com/file/d/1yoLZX3B-U7NqFIs-6S4xSBZLE7XCHXbO/view?usp=sharing', 'toco los 4 puntos tratando de buscar profundidad en cada estacion. evito que la rodilla se vaya hacia adentro', coach_id),
    ('Seated Pancake', 'ACTIVACION', 'https://drive.google.com/file/d/1fWaSy8MFvvUt7ObA3A7EBlulUX2GP8cI/view?usp=sharing', 'rodillas extendidas, mas facil si se semiflexionan.  saco cola y pecho.', coach_id),
    ('Dynamic Pigeon', 'ACTIVACION', 'https://drive.google.com/file/d/1gHSb7CfkVRY_NufNL-smcFv4nhdoMonB/view?usp=sharing', 'Bajo cadera lo mas posible. evito sentarme SOBRE la pierna adelantada.', coach_id),
    ('Shoulder Ext/Flex/Ad.', 'ACTIVACION', 'https://drive.google.com/file/d/1oRZrDqzsX3v1yNBtCiudsMiyXaZjnzei/view?usp=sharing', 'codos completamente extendidos. EVITO arquear espalda en todo momento.', coach_id),
    ('Sumo Walk (Diagonal)', 'ACTIVACION', 'https://drive.google.com/file/d/1gm2mtvegHhhxvFFZFV8i4GFbUTw3JT3W/view?usp=sharing', 'trato de no destensar del todo la banda', coach_id),
    ('Open Book', 'ACTIVACION', 'https://drive.google.com/file/d/1YUhSqsmI3EhK5b2N2C-XvlHpOewIgNCz/view?usp=sharing', 'junto escapulas en maxima apertura. evito levantar los hombros (pegarlos a la cabeza)', coach_id),
    ('Spiderman Apoyo Y Desapoyo Rodilla.', 'ACTIVACION', 'https://drive.google.com/file/d/1pLPqVxGT7FpUeHkMu69qWAGJOUDCKVKV/view?usp=sharing', 'Pie a la altura de la mano. esaplda derecha. rodilla de atras se flexiona y se extiende  por completo.', coach_id),
    ('Plane Hip Mobility', 'ACTIVACION', 'https://drive.google.com/file/d/1twphk7ICnoOluoekrLrD2ETaqRvJ9NLO/view?usp=sharing', 'Busco la rotacion mas amplia de cadera posible, tanto  como  para rotarla externamente como internamente.', coach_id),
    ('Single Glute Raises', 'ACTIVACION', 'https://drive.google.com/file/d/1qtbIvKoupTb5AfQct6gmH8Lo3o4lRe1V/view?usp=sharing', 'cadera alineada siempre. rodillas a la misma altura. brazos hacen presion hacia abajo.', coach_id),
    ('Pull Apart Diagonal', 'ACTIVACION', 'https://drive.google.com/file/d/1v6TbbPJE5XCVoM9CDXT14WKM7Cv8M8-W/view?usp=sharing', 'Palma de abajo mira adelante. codos extendidos siempre. NO ARQUEO ESPALDA', coach_id),
    ('Single Glute Raises + Abd', 'ACTIVACION', 'https://drive.google.com/file/d/1d8htn6-aLrXz6RF-eNocVx9BpBprJ97s/view?usp=sharing', 'CADERA ALINEADA SIEMPRE. cuando separo las rodillas mantengo estable la otra. al bajar no descargo peso', coach_id),
    ('Jefferson', 'ACTIVACION', 'https://drive.google.com/file/d/1FF_VPMG7EcKj2y-S4rZqfUunQzYnyBR8/view?usp=drive_link', 'trato de bajar vertebra por vertebra, rodillas siempre extendidas , peso distribuido en TODA la planta del pie', coach_id),
    ('Gato Bueno Malo', 'ACTIVACION', 'https://drive.google.com/file/d/135v96rVMYCalMw77IFWxERpkz5uiU4CP/view?usp=sharing', 'meto cola y cabeza subiendo columna al techo y luego al revez, mirada arriba saaco cola y panza al suelo.', coach_id),
    ('Plancha Frontal A Lateral', 'CORE', 'https://drive.google.com/file/d/1eb88L-yhYhDK9kwOZRPHqIAljamC-kAG/view?usp=sharing', 'NO SEGMENTO. muevo cadera y torso todo junto. tomo aire abajo mantengo al subir y mientras bajo suelto ajustando el abdomen', coach_id),
    ('Roll Out Fitball', 'CORE', 'https://drive.google.com/file/d/12-2G51RR6JalLrX1O9eTqvT7M2TkInTv/view?usp=sharing', 'cuerpo como plancha todo el tiempo. APLICO BRACING.', coach_id),
    ('Halo Split', 'CORE', 'https://drive.google.com/file/d/1THnuZ6NNxo8WkXVNOCbL0L2wxUtWxwjS/view?usp=sharing', 'RODILLA APOYADA. se trata de no mover el torso para no compensar el movimiento de brazos. movimiento completo y circular a la altura del cuello siempre. agarre pegado mas dificil que con manos mas separadas a la pesa rusa', coach_id),
    ('Hollow', 'CORE', 'https://drive.google.com/file/d/1EYxcFYnJywGE_Fv7eQYF9Ysbk8mOlBas/view?usp=sharing', 'Tomo aire abajo, mantengo al subir y ajusto gluteos. suelto el aire ajustando el abdomen como si me fueran a pegar. suelto el aire con fuerza mientras bajo', coach_id),
    ('Plancha En Fitball', 'CORE', 'https://drive.google.com/file/d/1YBBNY5vioiMDaOk5UqcDDowsZEF2th4v/view?usp=sharing', 'rechazo la pelota, codos a altura de hombro y mantengo posicion ajustando el abdomen para que la cadera no caiga. APLICO BRACING. mientras mas juntos los pies mas dificil', coach_id),
    ('Almeja', 'CORE', 'https://drive.google.com/file/d/1tFQCHeDwD7ZcgWj3dOoy7rCYfrwuOW_X/view?usp=sharing', 'rodilla cadera y hombro alineado. meto cola y trato de llevar el pupo a la espalda (trabo abdomen)', coach_id),
    ('Pallof Press', 'CORE', 'https://drive.google.com/file/d/1E-mlwTvhLPsjkChGF32r8o0UoFk_njFF/view?usp=sharing', 'APLICO BRACING. mentengo aire adelante unos 2 a 3 seg y vuelvo. hombro y cadera miran hacia adelante', coach_id),
    ('Superman En Plancha', 'CORE', 'https://drive.google.com/file/d/172DV9ctp7teo0dN2VzdyS6LTBksTUde5/view?usp=sharing', 'aplico bracing. tomo aire abajo mantengo al subir y suelto al bajar. mantener neutra la columna (no quebrar espalda baja). NO ABRIR CADERA.', coach_id),
    ('Molino Arrodillada', 'CORE', 'https://drive.google.com/file/d/13DIEjQctycqGTph1xRBQnk0kdlOwqtms/view?usp=sharing', 'hacerlo apoyando mano. aplico bracing. pesa de 6 u 8 kilos para empezar', coach_id),
    ('Plancha Sierra Fitball', 'CORE', 'https://drive.google.com/file/d/1ly54H6xd-FFdiwynu5XlR9-yQ73PjgzO/view?usp=sharing', 'tomo aire codos a altura de hombro, cuando adelanto mantengo y cuando vuelvo suelto AJUSTANDO abdomen. extiendo codos siempre y cuando no se pierda tecnica (no claudique cadera o arquee espalda)', coach_id),
    ('Ruedita', 'CORE', 'https://drive.google.com/file/d/1ldpul-7s4AQjPIq3kSyvkWLk9TpvIETv/view?usp=sharing', 'NO encojo hombros . tomo aire atras. mantengo al bajar y suelto casi arriba.  desde rodilla a cabeza una linea recta', coach_id),
    ('Plancha Lateral Junto Codo Con Rodilla', 'CORE', 'https://drive.google.com/file/d/1qR3_ScKAoUijfDffNJQ3dRRM52J7YWfY/view?usp=sharing', 'evito que cadera caiga. tomo aire mantengo al juntar y suelto al extender. cadera alineada.', coach_id),
    ('Trx Plank Forearm', 'CORE', 'https://drive.google.com/file/d/1FhZkJXq8jX9P3F9IWo57AUHrCEJ24yXE/view?usp=sharing', 'codos a altura de hombro. pies flexionados. ajusto gluteo y abdomen. aplico bracing', coach_id),
    ('Plancha Trx', 'CORE', 'https://drive.google.com/file/d/1sNEWMs4ipS4o1DnzVXbVJ4HjiDmw6OaT/view?usp=sharing', 'pies flexionados.  empujo el suelo.  manos a altura del hombro.', coach_id),
    ('Pallof Press Isometrico Polea', 'CORE', 'https://drive.google.com/file/d/1ktN93Q6HDaZKKC-4LLvHH3sSOwuecmvZ/view?usp=sharing', 'mantengo posicion, codos extendidos completamente, aplico bracing, trato de no compensar con hombros (elevandolos) o con cadera (ladeandola)', coach_id),
    ('Escaladodres Cruzados', 'CORE', 'https://drive.google.com/file/d/1OZsOi1QlbD-9jVNBM2-Uh1PffaY5aY28/view?usp=drive_link', 'ta re bueno el del video. AHREX. mano a altura de hombro, que no se caiga la cadera. tomo aire atras mantengo al adelantar rodilla y suelto al volver', coach_id),
    ('Bicho Muerto Bi. Con Peso', 'CORE', 'https://drive.google.com/file/d/1wcOpZK7f0Jm4NCt2G1-Bq-0ybxUi08NN/view?usp=sharing', 'Tomo aire arriba ajusto gluteo. mantengo aire al bajar y suelto al subir contrayendo abdomen. controlo movimiento, al bajar brazos y piernas NO tocan el suelo.', coach_id),
    ('Plancha Lateral Copenaghe', 'CORE', 'https://drive.google.com/file/d/1HEKS_uU9swRc5oDNBUlra_A_VKmZo14_/view?usp=sharing', 'Mientras la pierna del cajon mas apoyo tenga sobre el cajon mas facil. extenderla completamente. opcion facil elevar la rodilla de abajo a la altura de la otra. mas complejo flexionar la pierna libre hacia adelante. controlar cadera q no se ladee.', coach_id),
    ('Dead Bug Powerband', 'CORE', 'https://drive.google.com/file/d/1wEmid1bqur8hCLnwXkxHGT_U7PWuSFDa/view?usp=sharing', 'tomo aire arriba, mantengo al bajar y suelto al subir ajustando el abdomen. los pies buscan el suelo pero solo ROZAN con los talones el suelo, no se descarga el peso en ningun momento. avisar si hay dolor lumbar', coach_id),
    ('Pallof Press Desplazamiento', 'CORE', 'https://drive.google.com/file/d/1EbBYldZvKLa5XVJyEitml45y_BqaizX2/view?usp=sharing', 'manos a la altura del pecho y al centro del cuerpo, pasos cortos me desplazo y vuelvo. tomo aire antes de desplazarme, mantengo una vez que llego a la max extension suelto, ahi mismo tomo aire y vuelvo manteniendo.', coach_id),
    ('Lift Pulley', 'CORE', 'https://drive.google.com/file/d/1RZT7Jr-F6jMHHaii4k5fEzNa_W3OjPfa/view?usp=sharing', 'pierna mas alejada a la polea adelantada. aplico bracing, tomo aire abajo mantengo arriba y suelto al volver ajustando abdomen, al subir roto levemente y al volver controlo el movimiento lo mas lento posible.', coach_id),
    ('Dead Bug W/Isometric  Hand To Knee Press', 'CORE', 'https://drive.google.com/file/d/1-lEUJ6iYsP3VMh8gEdNw4PNMTX5ZlfbD/view?usp=sharing', 'mano en rodilla contraria, fuerzas opuestas  altas e iguales todo el tiempo. tomo aire arriba, mantengo al bajar brazo y pierna contraria  y suelto al subir, todas seguidas  a un lado luego al otro', coach_id),
    ('Fitball Plank', 'CORE', 'https://drive.google.com/file/d/1_Gs4WEUkn8O18q7n71jMHumu45tQ4IVp/view?usp=sharing', 'opcion facil codos a la altura del hombro, mientras mas adealnte los codos mas complejos. busco altura donde controle la cadera. RECHAZO LA PELOTA.', coach_id),
    ('Almeja Dinamica', 'CORE', 'https://drive.google.com/file/d/16h8CBGWneX2encgi_8C_UgejtgXtAntb/view?usp=sharing', 'rodilla y codo alineados. cadera por atras. tomo aire abajo mantengo al subir y alineo cadera con rodilla y codo. AJUSTO GLUTEOS.', coach_id),
    ('Plancha Plus', 'CORE', 'https://drive.google.com/file/d/1MiUgMT61bi0RiaIllBGbimq4JdC5q6OK/view?usp=sharing', 'ajusto abdomen y gluteo para que el movimiento sea solo de escapulas. cadera no se cae.', coach_id),
    ('Reverse Lunge', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1_C_wIWpO16poqegXLSrXx9MhBhLxyZUl/view?usp=sharing', 'rodillas hacia afuera. planta del pie completo apoyo. hombros hacia atras', coach_id),
    ('Sentadilla Con Barra', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1ODNu_P4ebIhjsmUyqhQ2HYn5lW9nWGVu/view?usp=sharing', 'torso hacia atras cuando bajo. busco profundidad. completo apoyo plantar. base en los pies minima. subo EMPUJANDO EL SUELO rodillas hacia afuera y derecha.', coach_id),
    ('Bulgaras', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1yXvo1NX2PPx9q90gslLXHgXRK5wybiNv/view?usp=sharing', 'al descender, busco que la rodilla de atras toque el suelo o lo roce. rodilla de adelante en rotacion externa y busca pasar la punta del pie.', coach_id),
    ('Pistol Squat', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1JBKmxHpVSKJ6U-RVgHVIo7xsV6ETYq13/view?usp=sharing', 'trx solo ayuda para estabilidad, fuerza de pierna para subir empujando el suelo (NO HAGO FUERZA CON BRAZOS)', coach_id),
    ('Sentadilla Split', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1kVy9oT-Yr8JhA5YJyYjCi6Z1e071363-/view?usp=sharing', 'parada me dejo caer para establecer distancia. al bajar, rodilla de adelante hacia afuera y deberia quedar en angulo de 90 grados. extiendo completamente al subir', coach_id),
    ('Sentadilla Rack', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1aXOjFgdgrQkHm1Rw1NCDfaga3gERPqCH/view?usp=sharing', 'sin supercificie. bajo lo mas posible siempre y cuando todo el pie este apoyado en todo momento y torso no se vaya adelante (para eso adelanto rodillas)', coach_id),
    ('Goblet Sq', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1WTk5cmP9aKoRdfgBgzTFtikrfpp2nFqT/view?usp=sharing', 'COLOCAR SUPERFICIE EN TALONES. hacer fuerza con torso para bajar derecha. bajar hasta donde se pueda controlar el torso y el compleyo apoyo plantar', coach_id),
    ('Step Down', 'KNEE DOMINANT', 'https://drive.google.com/file/d/16EVUTX-P_T_kG_ZfymM4nZIl-MFKgHyr/view?usp=sharing', 'rodilla del cajon siempre hacia afuera y adelante. bajo hasta donde pueda controlar subida. evito arquearme mucho con espalda', coach_id),
    ('Lateral Squat Db', 'KNEE DOMINANT', 'https://drive.google.com/file/d/1X6PqqmWK_3dg_YsVBiHW6hOiVN2n6B7j/view?usp=sharing', 'CON STEP. bajar lo mas posible siempre y cuando al volver no se compense con TRONCO (ladearlo para subir). CONTROLO cadera que baje bien derecha. subo con toda, lo mas rapido posible.', coach_id),
